186→    .slice()
187→    .sort((a, b) => b.confidence - a.confidence)
188→    .slice(0, 10)
189→    .map((entity) => `${entity.kind}: ${entity.text} (${entity.confidence.toFixed(2)})`);
190→  const toolLines = tools.slice(0, 10).map((tool) => `tool: ${tool}`);
