196→  if (anchors.length === 0) {
197→    return [];
198→  }
199→
200→  return suggestions.filter((suggestion) => includesAnyAnchor(suggestion, anchors));
201→}
202→
203→function includesAnyAnchor(suggestion: string, anchors: string[]): boolean {
204→  const normalizedSuggestion = normalizeForAnchorMatch(suggestion);
205→  for (const anchor of anchors) {
206→    const normalizedAnchor = normalizeForAnchorMatch(anchor);
207→    if (normalizedAnchor.length === 0) {
208→      continue;
209→    }
