  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { OnboardingAction, OnboardingState } from "../../shared/contracts";
  3→
  4→export type WorkspaceRow = {
  5→  id: RecordId<"workspace", string>;
  6→  name: string;
  7→  status: string;
  8→  onboarding_complete: boolean;
  9→  onboarding_turn_count: number;
 10→  onboarding_summary_pending: boolean;
 11→};
 12→
 13→type OnboardingCounts = {
 14→  projectCount: number;
 15→  personCount: number;
 16→  decisionCount: number;
 17→  questionCount: number;
 18→};
 19→
 20→export function toOnboardingState(workspace: WorkspaceRow): OnboardingState {
 21→  if (workspace.onboarding_complete) {
 22→    return "complete";
 23→  }
 24→  if (workspace.onboarding_summary_pending) {
 25→    return "summary_pending";
 26→  }
 27→  return "active";
 28→}
 29→
 30→export async function transitionOnboardingState(input: {
 31→  surreal: Surreal;
 32→  workspaceRecord: RecordId<"workspace", string>;
 33→  workspace: WorkspaceRow;
 34→  onboardingAction?: OnboardingAction;
 35→  now: Date;
 36→}): Promise<OnboardingState> {
 37→  if (input.workspace.onboarding_complete) {
 38→    return "complete";
 39→  }
 40→
 41→  if (input.workspace.onboarding_summary_pending) {
 42→    if (input.onboardingAction === "finalize_onboarding") {
 43→      await input.surreal.update(input.workspaceRecord).merge({
 44→        onboarding_complete: true,
 45→        onboarding_summary_pending: false,
 46→        onboarding_completed_at: input.now,
 47→        updated_at: input.now,
 48→      });
 49→      return "complete";
 50→    }
 51→
 52→    return "summary_pending";
 53→  }
 54→
 55→  const counts = await loadOnboardingCounts(input.surreal, input.workspaceRecord);
 56→  const minimumGraphReady =
 57→    counts.projectCount >= 1 && counts.personCount >= 1 && counts.decisionCount + counts.questionCount >= 1;
 58→
 59→  if (minimumGraphReady || input.workspace.onboarding_turn_count >= 7) {
 60→    await input.surreal.update(input.workspaceRecord).merge({
 61→      onboarding_summary_pending: true,
 62→      updated_at: input.now,
 63→    });
 64→    return "summary_pending";
 65→  }
 66→
 67→  return "active";
 68→}
 69→
 70→async function loadOnboardingCounts(
 71→  surreal: Surreal,
 72→  workspaceRecord: RecordId<"workspace", string>,
 73→): Promise<OnboardingCounts> {
 74→  const [projectRows] = await surreal
 75→    .query<[Array<{ id: RecordId<"project", string> }>]>(
 76→      "SELECT id FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
 77→      {
 78→        workspace: workspaceRecord,
 79→      },
 80→    )
 81→    .collect<[Array<{ id: RecordId<"project", string> }>]>() ;
 82→
 83→  const [personRows] = await surreal
 84→    .query<[Array<{ id: RecordId<"person", string> }>]>(
 85→      "SELECT id FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
 86→      {
 87→        workspace: workspaceRecord,
 88→      },
 89→    )
 90→    .collect<[Array<{ id: RecordId<"person", string> }>]>() ;
 91→
 92→  const [decisionRows] = await surreal
 93→    .query<[Array<{ id: RecordId<"decision", string> }>]>(
 94→      [
 95→        "SELECT id",
 96→        "FROM decision",
 97→        "WHERE id IN (",
 98→        "  SELECT VALUE `in`",
 99→        "  FROM belongs_to",
100→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
101→        ");",
102→      ].join(" "),
103→      { workspace: workspaceRecord },
104→    )
105→    .collect<[Array<{ id: RecordId<"decision", string> }>]>() ;
106→
107→  const [questionRows] = await surreal
108→    .query<[Array<{ id: RecordId<"question", string> }>]>(
109→      [
110→        "SELECT id",
111→        "FROM question",
112→        "WHERE id IN (",
113→        "  SELECT VALUE `in`",
114→        "  FROM belongs_to",
115→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
116→        ");",
117→      ].join(" "),
118→      { workspace: workspaceRecord },
119→    )
120→    .collect<[Array<{ id: RecordId<"question", string> }>]>() ;
121→
122→  return {
123→    projectCount: projectRows.length,
124→    personCount: personRows.length,
125→    decisionCount: decisionRows.length,
126→    questionCount: questionRows.length,
127→  };
128→}
129→
130→export async function loadOnboardingSummary(
131→  surreal: Surreal,
132→  workspaceRecord: RecordId<"workspace", string>,
133→): Promise<string> {
134→  const [projectRows] = await surreal
135→    .query<[Array<{ name: string }>]>(
136→      "SELECT name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace) LIMIT 8;",
137→      { workspace: workspaceRecord },
138→    )
139→    .collect<[Array<{ name: string }>]>() ;
140→
141→  const [personRows] = await surreal
142→    .query<[Array<{ name: string }>]>(
143→      "SELECT name FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace) LIMIT 8;",
144→      { workspace: workspaceRecord },
145→    )
146→    .collect<[Array<{ name: string }>]>() ;
147→
148→  const [decisionRows] = await surreal
149→    .query<[Array<{ summary: string; created_at: Date | string }>]>(
150→      [
151→        "SELECT summary, created_at",
152→        "FROM decision",
153→        "WHERE id IN (",
154→        "  SELECT VALUE `in`",
155→        "  FROM belongs_to",
156→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
157→        ")",
158→        "ORDER BY created_at DESC",
159→        "LIMIT 8;",
160→      ].join(" "),
161→      { workspace: workspaceRecord },
162→    )
163→    .collect<[Array<{ summary: string; created_at: Date | string }>]>() ;
164→
165→  const [questionRows] = await surreal
166→    .query<[Array<{ text: string; created_at: Date | string }>]>(
167→      [
168→        "SELECT text, created_at",
169→        "FROM question",
170→        "WHERE id IN (",
171→        "  SELECT VALUE `in`",
172→        "  FROM belongs_to",
173→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
174→        ")",
