  1→import { randomUUID } from "node:crypto";
  2→import { RecordId } from "surrealdb";
  3→import type {
  4→  CreateWorkspaceResponse,
  5→  DiscussEntitySummary,
  6→  OnboardingSeedItem,
  7→  WorkspaceBootstrapMessage,
  8→  WorkspaceBootstrapResponse,
  9→  WorkspaceConversationResponse,
 10→  SourceKind,
 11→  EntityKind,
 12→} from "../../shared/contracts";
 13→import { createEmbeddingVector } from "../graph/embeddings";
 14→import { readEntityName } from "../graph/queries";
 15→import { readEntityText } from "../extraction/entity-text";
 16→import type { GraphEntityRecord, SourceRecord } from "../extraction/types";
 17→import { HttpError } from "../http/errors";
 18→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
 19→import { parseCreateWorkspaceRequest } from "../http/parsing";
 20→import { jsonError, jsonResponse, toIsoString } from "../http/response";
 21→import type { ServerDependencies } from "../runtime/types";
 22→import { toOnboardingState } from "../onboarding/onboarding-state";
 23→import { resolveWorkspaceRecord } from "./workspace-scope";
 24→import { buildWorkspaceConversationSidebar } from "./conversation-sidebar";
 25→import { loadMessagesWithInheritance } from "../chat/branch-chain";
 26→
 27→type WorkspaceRow = {
 28→  id: RecordId<"workspace", string>;
 29→  name: string;
 30→  status: string;
 31→  onboarding_complete: boolean;
 32→  onboarding_turn_count: number;
 33→  onboarding_summary_pending: boolean;
 34→};
 35→
 36→type ProvenanceEdgeRow = {
 37→  id: RecordId<"extraction_relation", string>;
 38→  in: SourceRecord;
 39→  out: GraphEntityRecord;
 40→  confidence: number;
 41→  extracted_at: Date | string;
 42→};
 43→
 44→export function createWorkspaceRouteHandlers(deps: ServerDependencies): {
 45→  handleCreateWorkspace: (request: Request) => Promise<Response>;
 46→  handleWorkspaceBootstrap: (workspaceId: string) => Promise<Response>;
 47→  handleWorkspaceSidebar: (workspaceId: string) => Promise<Response>;
 48→  handleWorkspaceConversation: (workspaceId: string, conversationId: string) => Promise<Response>;
 49→} {
 50→  return {
 51→    handleCreateWorkspace: (request: Request) => handleCreateWorkspace(deps, request),
 52→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 53→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
 54→    handleWorkspaceConversation: (workspaceId: string, conversationId: string) =>
 55→      handleWorkspaceConversation(deps, workspaceId, conversationId),
 56→  };
 57→}
 58→
 59→async function handleCreateWorkspace(deps: ServerDependencies, request: Request): Promise<Response> {
 60→  const startedAt = performance.now();
 61→  logInfo("workspace.create.started", "Workspace creation started");
 62→
 63→  let body: unknown;
 64→  try {
 65→    body = await request.json();
 66→  } catch {
 67→    return jsonError("Request body must be valid JSON", 400);
 68→  }
 69→
 70→  const parsed = parseCreateWorkspaceRequest(body);
 71→  if (!parsed.ok) {
 72→    return jsonError(parsed.error, 400);
 73→  }
 74→
 75→  logDebug("http.request.validated", "Workspace request validated");
 76→
 77→  const now = new Date();
 78→  const workspaceId = randomUUID();
 79→  const conversationId = randomUUID();
 80→  const ownerId = randomUUID();
 81→
 82→  const workspaceRecord = new RecordId("workspace", workspaceId);
 83→  const conversationRecord = new RecordId("conversation", conversationId);
 84→  const ownerRecord = new RecordId("person", ownerId);
 85→  const starterMessageRecord = new RecordId("message", randomUUID());
 86→  const starterSuggestions = [
 87→    "Describe your primary project and goal",
 88→    "Share the biggest current bottleneck",
 89→    "Upload a plan or spec to extract",
 90→  ];
 91→
 92→  const starterMessage = [
 93→    `Hey ${parsed.data.ownerDisplayName}!`,
 94→    "I'm ready to help you build out your workspace.",
 95→    "Tell me about what you're working on - what's the main project or business you want to track here?",
 96→    "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
 97→  ].join(" ");
 98→
 99→  const transaction = await deps.surreal.beginTransaction();
100→  try {
101→    await transaction.create(workspaceRecord).content({
102→      name: parsed.data.name,
103→      status: "active",
104→      onboarding_complete: false,
105→      onboarding_turn_count: 0,
106→      onboarding_summary_pending: false,
107→      onboarding_started_at: now,
108→      created_at: now,
109→      updated_at: now,
110→    });
111→
112→    const ownerEmbedding = await createEmbeddingVector(
113→      deps.embeddingModel,
114→      parsed.data.ownerDisplayName,
115→      deps.config.embeddingDimension,
116→    );
117→    await transaction.create(ownerRecord).content({
118→      name: parsed.data.ownerDisplayName,
119→      ...(ownerEmbedding ? { embedding: ownerEmbedding } : {}),
120→      created_at: now,
121→      updated_at: now,
122→    });
123→
124→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
125→      role: "owner",
126→      added_at: now,
127→    }).output("after");
128→
129→    await transaction.create(conversationRecord).content({
130→      createdAt: now,
131→      updatedAt: now,
132→      workspace: workspaceRecord,
133→      source: "onboarding",
134→      title: "Onboarding",
135→      title_source: "message",
136→    });
137→
138→    await transaction.create(starterMessageRecord).content({
139→      conversation: conversationRecord,
140→      role: "assistant",
141→      text: starterMessage,
142→      suggestions: starterSuggestions,
143→      createdAt: now,
144→    });
145→
146→    await transaction.commit();
147→  } catch (error) {
148→    await transaction.cancel();
149→    logError("workspace.create.failed", "Workspace creation failed", error, {
150→      workspaceId,
151→      conversationId,
152→    });
153→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
154→    return jsonError(errorText, 500);
155→  }
156→
157→  const response: CreateWorkspaceResponse = {
158→    workspaceId,
159→    workspaceName: parsed.data.name,
160→    conversationId,
161→    onboardingComplete: false,
162→  };
163→
164→  logInfo("workspace.create.completed", "Workspace creation completed", {
165→    workspaceId,
166→    conversationId,
167→    durationMs: elapsedMs(startedAt),
168→  });
169→
170→  return jsonResponse(response, 200);
171→}
172→
173→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
174→  const startedAt = performance.now();
175→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
176→
177→  try {
178→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
179→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
180→    if (!workspace) {
181→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
182→    }
183→
184→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
185→    const conversationId = conversationRecord.id as string;
186→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
187→
188→    const messages = rawMessages.map((row) => ({
189→      id: row.id,
190→      role: row.role,
191→      text: row.text,
192→      createdAt: toIsoString(row.createdAt),
193→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
194→      ...(row.inherited ? { inherited: true } : {}),
195→    } satisfies WorkspaceBootstrapMessage));
196→
197→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
198→    const onboardingState = toOnboardingState(workspace);
199→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
200→
201→    const payload: WorkspaceBootstrapResponse = {
202→      workspaceId: workspace.id.id as string,
203→      workspaceName: workspace.name,
204→      onboardingComplete: workspace.onboarding_complete,
205→      onboardingState,
206→      conversationId: conversationRecord.id as string,
207→      messages,
208→      seeds,
209→      sidebar,
210→    };
211→
212→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
213→      workspaceId,
214→      conversationId: conversationRecord.id as string,
215→      messageCount: messages.length,
216→      seedCount: seeds.length,
217→      durationMs: elapsedMs(startedAt),
218→    });
219→
220→    return jsonResponse(payload, 200);
221→  } catch (error) {
222→    if (error instanceof HttpError) {
223→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
224→        workspaceId,
225→        statusCode: error.status,
226→      });
227→      return jsonError(error.message, error.status);
228→    }
229→
230→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
231→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
232→    return jsonError(errorText, 500);
233→  }
234→}
235→
236→async function resolveWorkspaceBootstrapConversation(
237→  deps: ServerDependencies,
238→  workspaceRecord: RecordId<"workspace", string>,
239→): Promise<RecordId<"conversation", string>> {
240→  const [onboardingRows] = await deps.surreal
241→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
242→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
243→      {
244→        workspace: workspaceRecord,
245→      },
246→    )
247→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
248→
249→  if (onboardingRows.length > 0) {
250→    return onboardingRows[0].id;
251→  }
252→
253→  const [latestRows] = await deps.surreal
254→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
255→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
256→      {
257→        workspace: workspaceRecord,
258→      },
259→    )
260→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
261→
262→  if (latestRows.length > 0) {
263→    return latestRows[0].id;
264→  }
265→
266→  const now = new Date();
267→  const conversationRecord = new RecordId("conversation", randomUUID());
268→  await deps.surreal.create(conversationRecord).content({
269→    createdAt: now,
270→    updatedAt: now,
271→    workspace: workspaceRecord,
272→    source: "onboarding",
273→  });
274→  return conversationRecord;
275→}
276→
277→async function loadWorkspaceSeeds(
278→  deps: ServerDependencies,
279→  workspaceRecord: RecordId<"workspace", string>,
280→  limit: number,
281→): Promise<OnboardingSeedItem[]> {
282→  const [edgeRows] = await deps.surreal
283→    .query<[ProvenanceEdgeRow[]]>(
284→      [
285→        "SELECT id, `in`, out, confidence, extracted_at",
286→        "FROM extraction_relation",
287→        "WHERE `in` IN array::concat(",
288→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
289→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
290→        ")",
291→        "ORDER BY extracted_at DESC",
292→        "LIMIT $limit;",
293→      ].join(" "),
294→      {
295→        workspace: workspaceRecord,
296→        limit,
297→      },
298→    )
299→    .collect<[ProvenanceEdgeRow[]]>();
300→
301→  const items: OnboardingSeedItem[] = [];
302→
303→  for (const edge of edgeRows) {
304→    const entityText = await readEntityText(deps.surreal, edge.out);
305→    if (!entityText) {
306→      continue;
307→    }
308→
309→    const sourceTable = edge.in.table.name;
310→    const entityTable = edge.out.table.name;
311→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
312→    const sourceLabel = await readSourceLabel(deps, edge.in);
313→
314→    items.push({
315→      id: edge.out.id as string,
316→      kind: entityTable as EntityKind,
317→      text: entityText,
318→      confidence: edge.confidence,
319→      sourceKind,
320→      sourceId: edge.in.id as string,
321→      ...(sourceLabel ? { sourceLabel } : {}),
322→    });
323→  }
324→
325→  return items;
326→}
327→
328→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
329→  const sourceTable = sourceRecord.table.name;
330→  if (sourceTable === "message") {
331→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
332→    if (!row) {
333→      return undefined;
334→    }
335→    return row.text.slice(0, 140);
336→  }
337→
338→  const chunk = await deps.surreal.select<{
339→    section_heading?: string;
340→    document: RecordId<"document", string>;
341→  }>(sourceRecord);
342→
343→  if (!chunk) {
344→    return undefined;
345→  }
346→
347→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
348→  if (!document) {
349→    return chunk.section_heading;
350→  }
351→
352→  if (chunk.section_heading) {
353→    return `${document.name} · ${chunk.section_heading}`;
354→  }
355→
356→  return document.name;
357→}
358→
359→async function handleWorkspaceSidebar(deps: ServerDependencies, workspaceId: string): Promise<Response> {
360→  const startedAt = performance.now();
361→  logInfo("workspace.sidebar.started", "Workspace sidebar request started", { workspaceId });
362→
363→  try {
364→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
365→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
366→
367→    logInfo("workspace.sidebar.completed", "Workspace sidebar request completed", {
368→      workspaceId,
369→      groupCount: sidebar.groups.length,
370→      unlinkedCount: sidebar.unlinked.length,
371→      durationMs: elapsedMs(startedAt),
372→    });
373→
374→    return jsonResponse(sidebar, 200);
375→  } catch (error) {
376→    if (error instanceof HttpError) {
377→      logWarn("workspace.sidebar.http_error", "Workspace sidebar failed with client-facing error", {
378→        workspaceId,
379→        statusCode: error.status,
380→      });
381→      return jsonError(error.message, error.status);
382→    }
383→
384→    logError("workspace.sidebar.failed", "Workspace sidebar request failed", error, { workspaceId });
385→    const errorText = error instanceof Error ? error.message : "workspace sidebar failed";
386→    return jsonError(errorText, 500);
387→  }
388→}
389→
390→async function handleWorkspaceConversation(
391→  deps: ServerDependencies,
392→  workspaceId: string,
393→  conversationId: string,
394→): Promise<Response> {
395→  const startedAt = performance.now();
396→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
397→    workspaceId,
398→    conversationId,
399→  });
400→
401→  try {
402→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
403→    const conversationRecord = new RecordId("conversation", conversationId);
404→    const conversation = await deps.surreal.select<{
405→      id: RecordId<"conversation", string>;
406→      workspace: RecordId<"workspace", string>;
407→      discusses?: RecordId;
408→    }>(conversationRecord);
409→
410→    if (!conversation) {
411→      throw new HttpError(404, `conversation not found: ${conversationId}`);
412→    }
413→
414→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
415→      throw new HttpError(400, "conversation does not belong to workspace");
416→    }
417→
418→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
419→
420→    const messages = rawMessages.map((row) => ({
421→      id: row.id,
422→      role: row.role,
423→      text: row.text,
424→      createdAt: toIsoString(row.createdAt),
425→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
426→      ...(row.inherited ? { inherited: true } : {}),
427→    } satisfies WorkspaceBootstrapMessage));
428→
429→    let discussEntity: DiscussEntitySummary | undefined;
430→    if (conversation.discusses) {
431→      const entityRecord = conversation.discusses as GraphEntityRecord;
432→      const name = await readEntityName(deps.surreal, entityRecord);
433→      if (name) {
434→        const entityRow = await deps.surreal.select<Record<string, unknown>>(entityRecord);
435→        discussEntity = {
