  1→import type { CreateWorkspaceRequest, OnboardingAction } from "../../shared/contracts";
  2→import { HttpError } from "./errors";
  3→
  4→const MAX_UPLOAD_BYTES = 2 * 1024 * 1024;
  5→const allowedUploadExtensions = new Set(["md", "txt"]);
  6→
  7→export type IncomingAttachment = {
  8→  fileName: string;
  9→  mimeType: string;
 10→  sizeBytes: number;
 11→  content: string;
 12→};
 13→
 14→export type ParsedIncomingMessage = {
 15→  clientMessageId: string;
 16→  workspaceId: string;
 17→  conversationId?: string;
 18→  text: string;
 19→  onboardingAction?: OnboardingAction;
 20→  attachment?: IncomingAttachment;
 21→  discussEntityId?: string;
 22→};
 23→
 24→const onboardingActions = new Set(["finalize_onboarding", "continue_onboarding"]);
 25→
 26→export function parseCreateWorkspaceRequest(body: unknown):
 27→  | { ok: true; data: CreateWorkspaceRequest }
 28→  | { ok: false; error: string } {
 29→  if (!body || typeof body !== "object") {
 30→    return { ok: false, error: "Body must be an object" };
 31→  }
 32→
 33→  const payload = body as Partial<CreateWorkspaceRequest>;
 34→
 35→  if (!payload.name || payload.name.trim().length === 0) {
 36→    return { ok: false, error: "name is required" };
 37→  }
 38→
 39→  if (!payload.ownerDisplayName || payload.ownerDisplayName.trim().length === 0) {
 40→    return { ok: false, error: "ownerDisplayName is required" };
 41→  }
 42→
 43→  return {
 44→    ok: true,
 45→    data: {
 46→      name: payload.name.trim(),
 47→      ownerDisplayName: payload.ownerDisplayName.trim(),
 48→    },
 49→  };
 50→}
 51→
 52→export async function parseIncomingMessageRequest(
 53→  request: Request,
 54→): Promise<{ ok: true; data: ParsedIncomingMessage } | { ok: false; error: string }> {
 55→  const contentType = request.headers.get("content-type") ?? "";
 56→
 57→  if (contentType.includes("multipart/form-data")) {
 58→    const formData = await request.formData();
 59→
 60→    const clientMessageIdValue = formData.get("clientMessageId");
 61→    const workspaceIdValue = formData.get("workspaceId");
 62→    const conversationIdValue = formData.get("conversationId");
 63→    const textValue = formData.get("text");
 64→    const onboardingActionValue = formData.get("onboardingAction");
 65→    const discussEntityIdValue = formData.get("discussEntityId");
 66→
 67→    if (typeof clientMessageIdValue !== "string" || clientMessageIdValue.trim().length === 0) {
 68→      return { ok: false, error: "clientMessageId is required" };
 69→    }
 70→
 71→    if (typeof workspaceIdValue !== "string" || workspaceIdValue.trim().length === 0) {
 72→      return { ok: false, error: "workspaceId is required" };
 73→    }
 74→
 75→    const text = typeof textValue === "string" ? textValue.trim() : "";
 76→
 77→    const fileValue = formData.get("file");
 78→    let attachment: IncomingAttachment | undefined;
 79→    if (fileValue instanceof File) {
 80→      try {
 81→        attachment = await parseIncomingAttachment(fileValue);
 82→      } catch (error) {
 83→        if (error instanceof HttpError) {
 84→          return { ok: false, error: error.message };
 85→        }
 86→        throw error;
 87→      }
 88→    }
 89→
 90→    if (!attachment && text.length === 0) {
 91→      return { ok: false, error: "text is required when no file is uploaded" };
 92→    }
 93→
 94→    const conversationId =
 95→      typeof conversationIdValue === "string" && conversationIdValue.trim().length > 0
 96→        ? conversationIdValue.trim()
 97→        : undefined;
 98→    const onboardingAction = typeof onboardingActionValue === "string" && onboardingActionValue.trim().length > 0
 99→      ? onboardingActionValue.trim()
