 17→export async function processChatMessage(input: {
 18→  deps: ServerDependencies;
 19→  conversationId: string;
 20→  messageId: string;
 21→  workspaceRecord: RecordId<"workspace", string>;
 22→  userMessageRecord: RecordId<"message", string>;
 23→  userText: string;
 24→  attachment?: IncomingAttachment;
 25→  onboardingAction?: OnboardingAction;
 26→  personRecord: RecordId<"person", string>;
 27→}): Promise<void> {
 28→  const startedAt = performance.now();
 29→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 30→    conversationId: input.conversationId,
 31→    messageId: input.messageId,
 32→    workspaceId: input.workspaceRecord.id as string,
 33→    hasAttachment: input.attachment !== undefined,
 34→  });
 35→
 36→  try {
 37→    const now = new Date();
 38→    const conversationRecord = new RecordId("conversation", input.conversationId);
 39→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 40→    if (!workspace) {
 41→      throw new Error("workspace not found");
 42→    }
 43→
 44→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 45→    if (!conversation) {
 46→      throw new Error("conversation not found");
 47→    }
 48→
 49→    // Check if this conversation is a branch and load inherited context
 50→    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
 51→    const isBranch = branchChain.length > 0;
 52→
 53→    let inheritedEntityIds: RecordId[] | undefined;
 54→    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;
 55→
 56→    if (isBranch) {
 57→      // For branches, load full message history including inherited messages
 58→      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
 59→      assistantContextRows = allMessages
 60→        .map((m) => ({
 61→          id: new RecordId("message", m.id),
 62→          role: m.role,
 63→          text: m.text,
 64→          createdAt: m.createdAt,
 65→        }))
 66→        .slice(-10);
 67→
 68→      // Derive inherited entity IDs from extraction_relations on inherited messages
 69→      const inheritedMsgIds = allMessages
 70→        .filter((m) => m.inherited)
 71→        .map((m) => new RecordId("message", m.id));
 72→
 73→      if (inheritedMsgIds.length > 0) {
 74→        const [entityRows] = await input.deps.surreal
 75→          .query<[Array<{ out: RecordId }>]>(
