  1→import { stepCountIs, streamText, type ModelMessage } from "ai";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { ExtractedEntity, ExtractedRelationship, OnboardingState } from "../../shared/contracts";
  4→import { logInfo, logError } from "../http/observability";
  5→import { buildChatContext, buildSystemPrompt, type ChatContext } from "./context";
  6→import { createChatAgentTools } from "./tools";
  7→
  8→type ConversationMessage = {
  9→  role: "user" | "assistant";
 10→  text: string;
 11→};
 12→
 13→type CollectedEntity = ExtractedEntity;
 14→type CollectedRelationship = ExtractedRelationship;
 15→
 16→export type ChatAgentResult = {
 17→  text: string;
 18→  collectedEntities: CollectedEntity[];
 19→  collectedRelationships: CollectedRelationship[];
 20→  toolCalls: Array<{ name: string; args: Record<string, unknown> }>;
 21→};
 22→
 23→export async function runChatAgent(input: {
 24→  surreal: Surreal;
 25→  model: any;
 26→  pmAgentModel: any;
 27→  analyticsAgentModel: any;
 28→  analyticsSurreal: Surreal;
 29→  embeddingModel: any;
 30→  embeddingDimension: number;
 31→  extractionModelId: string;
 32→  extractionModel: any;
 33→  extractionStoreThreshold: number;
 34→  conversationRecord: RecordId<"conversation", string>;
 35→  workspaceRecord: RecordId<"workspace", string>;
 36→  currentMessageRecord: RecordId<"message", string>;
 37→  latestUserText: string;
 38→  workspaceOwnerRecord?: RecordId<"person", string>;
 39→  personRecord: RecordId<"person", string>;
 40→  userMessageEmbedding?: number[];
 41→  inheritedEntityIds?: RecordId[];
 42→  discussesRecord?: RecordId;
 43→  messages: ConversationMessage[];
 44→  isOnboarding?: boolean;
 45→  onboardingState?: OnboardingState;
 46→  onToken: (token: string) => Promise<void> | void;
 47→  onReasoning?: (token: string) => Promise<void> | void;
 48→}): Promise<ChatAgentResult> {
 49→  const context = await buildChatContext({
 50→    surreal: input.surreal,
 51→    conversationRecord: input.conversationRecord,
 52→    workspaceRecord: input.workspaceRecord,
 53→    ...(input.userMessageEmbedding ? { userMessageEmbedding: input.userMessageEmbedding } : {}),
 54→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 55→      ? { inheritedEntityIds: input.inheritedEntityIds }
 56→      : {}),
 57→    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
 58→  });
 59→
 60→  const system = buildSystemPrompt(context, {
 61→    isOnboarding: input.isOnboarding,
 62→    onboardingState: input.onboardingState,
 63→  });
 64→
 65→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 66→    role: message.role,
 67→    content: message.text,
 68→  }));
 69→
 70→  const result = streamText({
 71→    model: input.model,
 72→    system,
 73→    messages: modelMessages,
 74→    tools: createChatAgentTools({
 75→      surreal: input.surreal,
 76→      pmAgentModel: input.pmAgentModel,
 77→      analyticsAgentModel: input.analyticsAgentModel,
 78→      analyticsSurreal: input.analyticsSurreal,
 79→      embeddingModel: input.embeddingModel,
 80→      embeddingDimension: input.embeddingDimension,
 81→      extractionModelId: input.extractionModelId,
 82→      extractionModel: input.extractionModel,
 83→      extractionStoreThreshold: input.extractionStoreThreshold,
 84→    }),
 85→    experimental_context: {
 86→      actor: "chat_agent",
 87→      humanPresent: true,
 88→      workspaceRecord: input.workspaceRecord,
 89→      conversationRecord: input.conversationRecord,
 90→      currentMessageRecord: input.currentMessageRecord,
 91→      latestUserText: input.latestUserText,
 92→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 93→      personRecord: input.personRecord,
 94→    },
 95→    stopWhen: stepCountIs(5),
 96→  });
 97→
 98→  let text = "";
 99→  const collectedEntities: CollectedEntity[] = [];
100→  const collectedRelationships: CollectedRelationship[] = [];
101→  const toolCalls: Array<{ name: string; args: Record<string, unknown> }> = [];
102→
103→  for await (const part of result.fullStream) {
104→    if (part.type === "reasoning-delta") {
105→      await input.onReasoning?.(part.text);
106→      continue;
107→    }
108→
109→    if (part.type === "text-delta") {
110→      text = `${text}${part.text}`;
111→      await input.onToken(part.text);
112→      continue;
113→    }
114→
115→    if (part.type === "tool-call") {
116→      logInfo("chat.agent.tool_call", "Chat agent invoked tool", part);
117→      toolCalls.push({ name: part.toolName, args: (part as any).input as Record<string, unknown> });
118→    }
119→
120→    if (part.type === "tool-result") {
121→      logInfo("chat.agent.tool_result", "Chat agent tool returned", part);
122→      const toolResult = part.output as Record<string, unknown> | undefined;
123→      if (toolResult) {
124→        if (Array.isArray(toolResult.extracted_entities)) {
125→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
126→        }
127→        if (Array.isArray(toolResult.extracted_relationships)) {
128→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
129→        }
130→      }
131→    }
132→
133→    if (part.type === "error") {
134→      logError("chat.agent.stream_error", "Chat agent stream error", part.error, {});
135→    }
136→  }
137→
138→  if (text.trim().length === 0) {
139→    text = await result.text;
140→  }
